css:
/* Kommissionierschein — Workflow-Streifen oben, Item-Tabelle mit Soll/
   Ist + Karton-Spalte, Signaturen unten. Schwerpunkt: Status auf einen
   Blick beim Durchlaufen Pick → Pack → QS → Versand. */

.sr-only {
  position: absolute;
  width: 1px; height: 1px;
  overflow: hidden;
  clip: rect(0 0 0 0);
}

.ks-workflow {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 3mm;
  margin: 4mm 0 6mm;
}
.ks-workflow__step {
  border: 0.3mm solid #d1d5db;
  border-radius: 1mm;
  padding: 3mm 4mm;
  min-height: 14mm;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
}
.ks-workflow__step-name {
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.4px;
  text-transform: uppercase;
  color: #6b7280;
}
.ks-workflow__step-stamp {
  font-size: 11pt;
  font-weight: 600;
  color: #111827;
  min-height: 6mm;
  border-bottom: 0.2mm dashed #d1d5db;
}

.ks-meta {
  margin-bottom: 4mm;
}
.ks-meta__dl {
  display: grid;
  grid-template-columns: repeat(2, max-content 1fr);
  gap: 1mm 4mm;
  margin: 0;
  font-size: 9.5pt;
}
.ks-meta__dl > div { display: contents; }
.ks-meta__dl dt {
  font-weight: 700;
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  color: #4b5563;
}
.ks-meta__dl dd { margin: 0; }
.ks-meta__addr dd { line-height: 1.35; }

.ks-instructions {
  margin: 4mm 0 6mm;
  padding: 3mm 5mm;
  background: rgba(245, 158, 11, 0.10);
  border: 0.3mm solid rgba(245, 158, 11, 0.4);
  border-radius: 1mm;
}
.ks-instructions h2 {
  margin: 0 0 1mm;
  font-size: 10pt;
  color: #92400e;
}
.ks-instructions p {
  margin: 0;
  font-size: 9.5pt;
  line-height: 1.4;
  color: #1f2937;
}

.ks-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
}
.ks-table thead th {
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  text-align: left;
  background: #f3f4f6;
  border-bottom: 0.4mm solid #6b7280;
  padding: 2mm 3mm;
  color: #374151;
}
.ks-table tbody td {
  padding: 2.5mm 3mm;
  border-bottom: 0.2mm solid #e5e7eb;
  vertical-align: middle;
}
.ks-table__col-loc {
  width: 22mm;
  font-weight: 700;
  font-family: monospace;
  font-size: 10pt;
  letter-spacing: 0.5pt;
}
.ks-table__col-sku    { width: 30mm; }
.ks-table__col-qty    {
  width: 18mm;
  text-align: right;
  font-variant-numeric: tabular-nums;
}
.ks-table__col-picked { width: 14mm; text-align: center; }
.ks-table__col-box    { width: 16mm; text-align: center; }

.ks-sku {
  font-family: monospace;
  font-size: 10pt;
  font-weight: 600;
}
.ks-ean {
  font-family: monospace;
  font-size: 8pt;
  color: #6b7280;
}
.ks-flags {
  display: flex;
  gap: 2mm;
  margin-top: 1mm;
  flex-wrap: wrap;
}
.ks-flag {
  font-size: 8pt;
  font-weight: 700;
  letter-spacing: 0.3px;
  padding: 0.5mm 2mm;
  border-radius: 1mm;
}
.ks-flag--hazard {
  background: rgba(239, 68, 68, 0.12);
  color: #991b1b;
}
.ks-flag--cold {
  background: rgba(59, 130, 246, 0.12);
  color: #1e40af;
}

.ks-picked-box {
  display: inline-block;
  width: 6mm;
  height: 6mm;
  border: 0.4mm solid #111827;
  border-radius: 0.5mm;
}
.ks-box-input {
  display: inline-block;
  width: 14mm;
  height: 6mm;
  border-bottom: 0.3mm solid #111827;
  font-family: monospace;
  font-weight: 600;
  padding-top: 1mm;
}

.ks-sigs {
  margin-top: 12mm;
}
.ks-sigs__table {
  width: 100%;
  border-collapse: collapse;
  font-size: 9.5pt;
}
.ks-sigs__table th {
  text-align: left;
  font-size: 8pt;
  text-transform: uppercase;
  letter-spacing: 0.3px;
  color: #6b7280;
  padding: 1mm 2mm;
  font-weight: 700;
  border-bottom: 0.2mm solid #d1d5db;
}
.ks-sigs__table tbody th {
  width: 25mm;
  text-transform: none;
  font-size: 10pt;
  color: #374151;
}
.ks-sigs__table tbody td {
  border-bottom: 0.3mm solid #111827;
  padding: 1mm 2mm;
  height: 10mm;
  vertical-align: bottom;
}
